-- ============================================
-- 产品使用说明数据
-- ============================================
INSERT INTO product_manuals (product_id, category, title, content, sort_order) VALUES
(1, '快速入门', 'AirPods快速入门指南', '# AirPods快速入门\n\n## 开箱检查\n- AirPods x 2\n- 充电盒 x 1\n- Lightning线 x 1\n- 说明书 x 1\n\n## 首次配对\n1. 打开iPhone蓝牙\n2. 打开充电盒盖\n3. 点击屏幕上的"连接"\n4. 完成配对\n\n## 日常使用\n- 双击耳机：播放/暂停\n- 取下一只：暂停播放\n- 放回充电盒：自动充电', 1),

(1, '连接设置', 'AirPods连接与配对详解', '# AirPods连接设置\n\n## 与iPhone配对\n1. 确保iPhone蓝牙已开启\n2. 将AirPods放入充电盒\n3. 打开盒盖\n4. 按住背面按钮至白灯闪烁\n5. 在iPhone上选择AirPods\n\n## 与其他设备配对\n### Android设备\n1. 打开蓝牙设置\n2. 按住充电盒背面按钮\n3. 从列表选择AirPods\n\n### Mac\n1. 点击菜单栏蓝牙图标\n2. 选择AirPods\n3. 点击"连接"', 2),

(2, '功能使用', 'AirPods Pro降噪与通透模式', '# 降噪与通透模式\n\n## 主动降噪\n- 阻隔外界噪音\n- 适合嘈杂环境\n- 长按耳机柄切换\n\n## 通透模式\n- 允许外界声音进入\n- 适合户外或交谈\n- 保持环境感知\n\n## 自适应音频\n- 自动调节降噪强度\n- 根据环境智能切换\n- 需在设置中开启\n\n## 设置方法\n1. 设置→蓝牙→AirPods\n2. 选择"噪音控制"\n3. 开启"自适应"', 3),

(3, '故障排除', 'AirPods常见问题解决', '# 常见问题解决\n\n## 连接问题\n**问题**: 连不上手机\n**解决**: \n1. 重启蓝牙\n2. 重置AirPods\n3. 忘记设备重新配对\n\n## 音质问题\n**问题**: 声音小或有杂音\n**解决**:\n1. 清洁扬声器网罩\n2. 检查耳塞贴合度\n3. 更新固件\n\n## 电池问题\n**问题**: 续航变短\n**解决**:\n1. 关闭人耳检测\n2. 降低音量\n3. 联系Pineapple支持更换电池', 4);

