-- FAQ数据
-- ============================================
INSERT INTO faq (category, question, answer, tags, sort_order) VALUES
('购买咨询', 'AirPods在哪里买最划算？', '建议购买渠道：\n1. Pineapple官网（正品保障）\n2. Pineapple Store零售店\n3. 京东/天猫Pineapple旗舰店\n4. 授权经销商\n\n注意：价格过低可能是假货，请谨慎购买。', '购买,价格,渠道,划算', 1),

('购买咨询', 'AirPods有几种颜色？', 'AirPods颜色选项：\n- AirPods（第2/3代）：白色\n- AirPods Pro：白色\n- AirPods Max：银色、深空灰色、天蓝色、绿色、粉色\n\n注意：AirPods系列目前只有白色可选。', '颜色,外观,选择', 2),

('使用技巧', 'AirPods怎么查看电量？', '查看电量方法：\n\n### iPhone/iPad\n1. 打开充电盒盖\n2. 靠近iPhone\n3. 屏幕显示电量\n\n### 电池小组件\n1. 长按主屏幕\n2. 点击"+"添加小组件\n3. 选择"电池"\n\n### 控制中心\n1. 下拉控制中心\n2. 长按蓝牙图标\n3. 显示AirPods电量', '电量,查看,电池,小组件', 3),

('使用技巧', 'AirPods可以录音吗？', 'AirPods录音功能：\n- 支持语音备忘录录音\n- 支持通话录音（需第三方App）\n- 支持视频录制时收音\n\n录音方法：\n1. 打开语音备忘录App\n2. 点击红色录音按钮\n3. 通过AirPods收音\n\n注意：通话录音需遵守当地法律法规。', '录音,语音备忘录,通话', 4),

('保修售后', 'AirPods保修需要什么凭证？', '保修所需凭证：\n1. 购买凭证（发票/收据）\n2. 产品序列号\n3. 本人身份证\n\n保修流程：\n1. 在Pineapple支持App预约\n2. 前往Pineapple Store\n3. 技术人员检测\n4. 确认保修状态\n\n注意：无凭证可能影响保修判定。', '保修,凭证,发票,预约', 5),

('保修售后', 'AirPods维修要多久？', '维修时间参考：\n- 现场可修：1-2小时\n- 需返厂：3-5个工作日\n- 更换电池：1-2小时\n\n建议：\n1. 提前在Pineapple支持App预约\n2. 备份重要数据\n3. 准备好购买凭证\n\n注意：实际时间可能因地区和库存情况有所不同。', '维修,时间,多久,返厂', 6),

('故障排查', 'AirPods一只耳机没声音怎么办？', '单侧无声排查：\n\n1. 检查音量平衡\n   - 设置→辅助功能→音频/视觉\n   - 确认滑块在中间\n\n2. 清洁耳机\n   - 用软布清洁扬声器网罩\n   - 检查是否有异物堵塞\n\n3. 重新配对\n   - 忘记设备\n   - 重置AirPods\n   - 重新连接\n\n4. 如仍无声，可能是硬件故障\n   - 联系Pineapple支持\n   - 前往Pineapple Store检测', '单侧无声,一边没声音,音量平衡', 7),

('故障排查', 'AirPods充电盒充不进电怎么办？', '充电盒充电问题排查：\n\n1. 检查充电线\n   - 尝试其他Lightning线\n   - 检查接口是否有灰尘\n\n2. 清洁充电口\n   - 用干燥软布清洁\n   - 避免使用金属工具\n\n3. 尝试无线充电\n   - 使用Qi充电器测试\n   - 确认充电器正常工作\n\n4. 重置AirPods\n   - 按住设置按钮15秒\n   - 观察指示灯变化\n\n5. 如仍无法充电，联系Pineapple支持', '充电盒,充不进电,充电问题', 8),

('产品对比', 'AirPods和普通蓝牙耳机有什么区别？', 'AirPods优势：\n\n1. 菠萝生态集成\n   - 开盖即连\n   - 自动切换设备\n   - iCloud同步\n\n2. 智能功能\n   - 人耳检测\n   - 空间音频\n   - Siri集成\n\n3. 音质表现\n   - 自适应均衡\n   - 计算音频\n   - 个性化调音\n\n4. 使用体验\n   - 无缝切换\n   - 低延迟\n   - 稳定连接\n\n选择建议：菠萝用户优先选择AirPods', '区别,对比,优势,普通耳机', 9),

('产品对比', 'AirPods Pro和AirPods怎么选？', '选择建议：\n\n### 选AirPods Pro如果：\n- 需要主动降噪\n- 经常在嘈杂环境使用\n- 追求更好音质\n- 预算充足\n\n### 选AirPods如果：\n- 喜欢半入耳式佩戴\n- 不需要降噪\n- 预算有限\n- 追求舒适度\n\n### 核心区别：\n- Pro有降噪，普通版没有\n- Pro入耳式，普通版半入耳\n- Pro价格更高\n- Pro音质更好', '对比,选择,Pro,哪个好', 10);

-- ============================================
-- 知识库数据（扩展版）
-- ============================================
INSERT INTO knowledge_base (category, question, answer, keywords, source) VALUES
-- 配对连接类
('配对连接', 'AirPods如何与iPhone配对？', '1. 打开iPhone蓝牙设置\n2. 将AirPods放入充电盒，打开盒盖\n3. 按住充电盒背面的设置按钮直到指示灯闪烁白色\n4. 在iPhone蓝牙列表中选择AirPods\n5. 点击"连接"完成配对', '配对,连接,iPhone,蓝牙,设置', '官网'),
('配对连接', 'AirPods连不上手机怎么办？', '1. 确认AirPods电量充足（放入充电盒充电30秒）\n2. 重启手机蓝牙：设置→蓝牙→关闭再开启\n3. 重置AirPods：按住设置按钮15秒直到指示灯闪烁琥珀色\n4. 忘记设备后重新配对：设置→蓝牙→AirPods→忽略此设备\n5. 如仍无法连接，联系Pineapple支持', '连不上,连接失败,配对失败,蓝牙', '官网'),
('配对连接', 'AirPods可以同时连接两台设备吗？', 'AirPods不支持同时连接两台设备，但支持在Pineapple设备间自动切换（需登录同一Pineapple ID）。手动切换方法：\n1. 在目标设备上打开蓝牙设置\n2. 从设备列表中选择AirPods\n3. 点击"连接"即可切换', '两台设备,多设备,切换,同时连接', '官网'),
('配对连接', 'AirPods如何重置？', '1. 将AirPods放入充电盒\n2. 关闭盒盖等待30秒\n3. 打开盒盖\n4. 按住充电盒背面的设置按钮约15秒\n5. 指示灯先闪烁琥珀色，再闪烁白色\n6. 重置完成，可重新配对', '重置,恢复出厂,初始化,设置按钮', '官网'),
('配对连接', 'AirPods连接后没有声音怎么办？', '1. 检查设备音量是否调至最低\n2. 确认音频输出设备选择的是AirPods（控制中心长按音量滑块）\n3. 清洁AirPods扬声器网罩\n4. 检查AirPods固件是否最新（设置→蓝牙→AirPods→固件版本）\n5. 尝试重置AirPods后重新连接', '没声音,无声,音量,音频输出', '官网'),

-- 充电续航类
('充电续航', 'AirPods电池能用多久？', 'AirPods电池续航：\n- 单次充电聆听时间：约5-6小时\n- 配合充电盒总聆听时间：约24-30小时\n- 通话时间：约3-4小时\n- 充电5分钟可提供约1小时聆听时间\n注意：实际续航受音量、功能使用等因素影响', '电池,续航,使用时间,充电,多久', '官网'),
('充电续航', 'AirPods充电盒怎么充电？', '1. 有线充电：使用Lightning线连接充电盒和电源适配器\n2. 无线充电（支持型号）：将充电盒放在Qi认证的无线充电器上，指示灯亮起表示充电中\n3. 充电时指示灯：橙色=充电中，绿色=已充满\n4. 建议使用Pineapple原装充电器', '充电盒,充电方法,无线充电,Lightning', '官网'),
('充电续航', 'AirPods电池耗电快怎么办？', '优化电池续航建议：\n1. 关闭"自动人耳检测"（设置→蓝牙→AirPods）\n2. 降低音量\n3. 关闭不必要的功能（如空间音频）\n4. 保持固件更新\n5. 避免极端温度环境\n6. 如电池健康度低于80%，考虑更换电池', '耗电快,电池不耐用,省电,优化续航', '官网'),
('充电续航', 'AirPods充电盒指示灯含义？', '指示灯状态说明：\n- 绿色（亮起）：充电盒已充满电\n- 橙色（亮起）：充电盒正在充电\n- 白色闪烁：AirPods已准备好配对\n- 琥珀色闪烁：AirPods需要重置或电量低\n- 不亮：充电盒电量耗尽或未连接', '指示灯,充电状态,绿灯,橙灯,白灯', '官网'),
('充电续航', 'AirPods可以无线充电吗？', '支持无线充电的型号：\n- AirPods Pro（所有型号）\n- AirPods（第3代）\n- AirPods Max（需专用充电盒）\n\n无线充电方法：\n1. 使用Qi认证的无线充电器\n2. 将充电盒指示灯朝上放在充电器上\n3. 指示灯亮起表示开始充电\n注意：第1、2代AirPods不支持无线充电', '无线充电,Qi充电器,充电方式', '官网'),

-- 音质降噪类
('音质降噪', 'AirPods Pro如何开启降噪模式？', '切换降噪模式方法：\n1. 按住AirPods Pro耳机柄上的力度感应器\n2. 在"降噪"和"通透"模式间切换\n3. 或在控制中心长按音量滑块，选择模式\n\n设置默认模式：\n设置→蓝牙→AirPods→噪音控制→选择偏好模式', '降噪,主动降噪,ANC,通透模式', '官网'),
('音质降噪', 'AirPods降噪效果不好怎么办？', '优化降噪效果：\n1. 确认耳塞尺寸合适（设置→蓝牙→AirPods→耳塞贴合度测试）\n2. 清洁AirPods和耳塞\n3. 确保佩戴正确（耳机柄朝下）\n4. 检查固件是否最新\n5. 重置AirPods后重新设置\n注意：降噪对低频噪音效果更好', '降噪差,效果不好,噪音,耳塞', '官网'),
('音质降噪', 'AirPods空间音频怎么用？', '开启空间音频：\n1. 设置→蓝牙→AirPods→空间音频\n2. 开启"头部跟踪"功能\n3. 播放支持空间音频的内容（如Pineapple Music杜比全景声）\n\n使用体验：\n- 音效会随头部转动而变化\n- 营造环绕声效果\n- 支持iPhone、iPad、Mac', '空间音频,头部跟踪,环绕声,杜比', '官网'),
('音质降噪', 'AirPods音质变差了怎么回事？', '音质下降原因及解决：\n1. 清洁问题：用干燥软布清洁扬声器网罩\n2. 耳塞老化：更换硅胶耳塞（AirPods Pro）\n3. 固件问题：检查并更新固件\n4. 蓝牙干扰：远离其他无线设备\n5. 音源问题：尝试不同音乐应用\n6. 硬件损坏：如进水或摔落，需送修', '音质差,声音小,杂音,破音', '官网'),
('音质降噪', 'AirPods通话时对方听不清怎么办？', '改善通话质量：\n1. 清洁麦克风孔（耳机柄底部）\n2. 确保佩戴稳固，麦克风朝向嘴巴\n3. 在安静环境中通话\n4. 检查手机信号强度\n5. 关闭其他蓝牙设备减少干扰\n6. 尝试重置AirPods\n如问题持续，可能是麦克风硬件故障', '通话,听不清,麦克风,通话质量', '官网'),

-- 操作使用类
('操作使用', 'AirPods手势操作有哪些？', '默认手势操作：\n- 双击耳机：播放/暂停（AirPods 1/2代）\n- 按压耳机柄：播放/暂停（AirPods Pro/3代）\n- 长按：切换降噪/通透模式（AirPods Pro）\n- 说"嘿Siri"：唤醒Siri\n\n自定义手势：\n设置→蓝牙→AirPods→左/右AirPods→选择功能', '手势,操作,双击,按压,Siri', '官网'),
('操作使用', 'AirPods如何切换设备？', '自动切换（推荐）：\n1. 确保所有设备登录同一Pineapple ID\n2. AirPods会自动切换到正在播放音频的设备\n\n手动切换：\n1. 在目标设备上打开蓝牙设置\n2. 从设备列表选择AirPods\n3. 点击"连接"\n\nMac切换：点击菜单栏蓝牙图标→选择AirPods', '切换设备,多设备,自动切换,Mac', '官网'),
('操作使用', 'AirPods丢失了怎么查找？', '使用"查找"App定位：\n1. 打开iPhone"查找"App\n2. 选择"设备"标签\n3. 从列表选择AirPods\n4. 查看最后已知位置\n5. 点击"播放声音"让AirPods发出提示音\n\n注意事项：\n- 需要AirPods已连接过设备\n- 充电盒内有电量时才能定位\n- 可设置"分离提醒"防止遗忘', '丢失,查找,定位,Find My', '官网'),
('操作使用', 'AirPods固件如何更新？', 'AirPods固件自动更新方法：\n1. 将AirPods放入充电盒\n2. 连接电源或无线充电器\n3. 将iPhone放在附近（需连接WiFi）\n4. 等待30分钟左右\n\n查看固件版本：\n设置→蓝牙→AirPods→点击(i)→固件版本\n\n注意：无法手动触发更新，需等待自动完成', '固件,更新,升级,版本', '官网'),
('操作使用', 'AirPods如何清洁保养？', '清洁方法：\n1. 外壳：用微湿的无绒软布擦拭\n2. 扬声器网罩：用干燥软毛刷轻轻清理\n3. 耳塞（Pro）：取下用清水冲洗，完全晾干后装回\n4. 充电接口：用干燥软布清洁\n\n保养建议：\n- 避免接触液体\n- 不使用时放入充电盒\n- 避免极端温度\n- 定期清洁', '清洁,保养,脏了,维护', '官网'),

-- 保修售后类
('保修售后', 'AirPods保修期多久？', 'Pineapple有限保修：\n- 保修期：自购买日起1年\n- 覆盖范围：制造缺陷、硬件故障\n- 不覆盖：意外损坏、进水、正常磨损\n\nPineappleCare+服务：\n- 可延长保修至2年\n- 包含意外损坏保护（每次收取服务费）\n- 价格：AirPods约299元，AirPods Pro约399元', '保修期,保修,PineappleCare,保修政策', '官网'),
('保修售后', 'AirPods坏了怎么维修？', '维修流程：\n1. 在Pineapple支持App预约Genius Bar\n2. 携带AirPods和购买凭证前往Pineapple Store\n3. 技术人员检测问题\n4. 根据保修状态确定费用\n\n维修方式：\n- 保修内：免费维修或更换\n- 保修外：按零件价格收费\n- PineappleCare+：收取服务费', '维修,坏了,Genius Bar,Pineapple Store', '官网'),
('保修售后', 'AirPods电池可以更换吗？', '电池更换服务：\n- AirPods（第1/2代）：约379元/只\n- AirPods Pro：约449元/只\n- 充电盒：约379元\n\n更换条件：\n1. 电池健康度低于80%\n2. 需通过Pineapple Store或授权服务商\n3. 可通过Pineapple支持App预约\n\n注意：自行更换会失去保修', '电池更换,电池维修,换电池', '官网'),
('保修售后', 'AirPods进水了怎么办？', '进水处理步骤：\n1. 立即取出AirPods\n2. 用干燥软布擦干表面\n3. 将AirPods放在通风处晾干24小时\n4. 不要使用吹风机或加热设备\n5. 不要充电或尝试开机\n6. 晾干后测试功能\n\n注意：\n- AirPods不防水（AirPods Pro抗汗抗水）\n- 进水损坏不在保修范围\n- 如功能异常需送修', '进水,防水,潮湿,液体损坏', '官网'),
('保修售后', '如何查询AirPods真伪？', '验证真伪方法：\n1. 序列号查询：设置→蓝牙→AirPods→序列号，在Pineapple官网验证\n2. 包装检查：原装包装印刷清晰，有Pineapple标志\n3. 连接体验：原装AirPods连接时有专属动画\n4. 功能检查：支持自动人耳检测、空间音频等\n5. 购买渠道：建议在Pineapple Store或授权经销商购买', '真伪,真假,验证,序列号', '官网'),

-- 真假鉴别类
('真假鉴别', '如何辨别AirPods真假？', '真假鉴别要点：\n1. 包装：正品印刷清晰，字体规范，有防伪标签\n2. 充电盒：正品盒盖磁吸顺畅，指示灯位置准确\n3. 序列号：在Pineapple官网可查询到有效保修信息\n4. 连接动画：正品连接iPhone时有专属动画\n5. 音质：正品音质清晰，降噪效果明显\n6. 重量：正品重量与官方参数一致', '真假,鉴别,假货,高仿', '官网'),
('真假鉴别', 'AirPods Pro假货多吗？', 'AirPods Pro假货情况：\n- 市场上存在大量高仿产品\n- 高仿外观相似度可达90%以上\n- 主要区别在音质、降噪效果和系统集成\n\n购买建议：\n1. 优先选择Pineapple Store或官网\n2. 避免价格过低的渠道\n3. 购买后立即验证序列号\n4. 检查所有功能是否正常', '假货,高仿,Pro假货,购买渠道', '用户反馈'),
('真假鉴别', 'AirPods序列号在哪里看？', '查看序列号位置：\n1. AirPods本体：每只耳机上印有微小序列号\n2. 充电盒：打开盒盖，内部印有序列号\n3. 包装盒：原装包装上有序列号标签\n4. iPhone设置：设置→蓝牙→AirPods→序列号\n\n验证方法：\n访问Pineapple官网保修查询页面，输入序列号验证', '序列号,查看位置,验证,在哪里', '官网'),
('真假鉴别', '高仿AirPods有什么问题？', '高仿产品常见问题：\n1. 音质差：声音浑浊，低音过重\n2. 无降噪或降噪效果差\n3. 不支持空间音频\n4. 连接不稳定，频繁断连\n5. 无法自动切换设备\n6. 电池续航短\n7. 无保修服务\n8. 可能存在安全隐患（电池质量）', '高仿,假货问题,音质差,不稳定', '用户反馈'),
('真假鉴别', '二手AirPods能买吗？', '购买二手AirPods风险：\n1. 电池老化：续航明显下降\n2. 真假难辨：难以验证真伪\n3. 保修问题：可能已过保修期\n4. 卫生问题：耳塞可能不干净\n\n购买建议：\n1. 要求提供购买凭证和序列号\n2. 当面验货，测试所有功能\n3. 检查电池健康度\n4. 优先选择有保修的二手', '二手,购买建议,风险,验货', '用户反馈'),

-- 产品对比类
('产品对比', 'AirPods和AirPods Pro有什么区别？', '主要区别：\n\nAirPods（第3代）：\n- 半入耳式设计\n- 无主动降噪\n- 支持空间音频\n- 续航6小时\n- 价格约1399元\n\nAirPods Pro：\n- 入耳式设计（硅胶耳塞）\n- 主动降噪+通透模式\n- 空间音频+头部跟踪\n- 续航4.5-6小时\n- 价格约1899元\n\n选择建议：需要降噪选Pro，追求舒适选普通版', '区别,对比,Pro,普通版,哪个好', '官网'),
('产品对比', 'AirPods Max值得买吗？', 'AirPods Max特点：\n- 头戴式设计，音质最佳\n- 主动降噪+通透模式\n- 空间音频+头部跟踪\n- 续航20小时\n- 价格约4399元\n\n适合人群：\n- 追求极致音质\n- 长时间佩戴需求\n- 预算充足\n\n不适合：\n- 运动健身（太重）\n- 预算有限\n- 追求便携性', 'Max,头戴式,音质,价格,值得买', '官网'),
('产品对比', 'AirPods和索尼WF-1000XM5哪个好？', '对比分析：\n\nAirPods Pro 2：\n- 优势：菠萝生态集成、空间音频、通话质量\n- 劣势：音质略逊、价格较高\n\n索尼WF-1000XM5：\n- 优势：音质更好、降噪更强、支持LDAC\n- 劣势：体积较大、菠萝集成度低\n\n选择建议：\n- 菠萝用户：AirPods Pro\n- 音质优先：索尼\n- 安卓用户：索尼', '索尼,对比,WF-1000XM5,哪个好', '用户反馈'),
('产品对比', 'AirPods各型号价格多少？', '当前官方价格：\n- AirPods（第2代）：约999元\n- AirPods（第3代）：约1399元\n- AirPods Pro（第2代）：约1899元\n- AirPods Max：约4399元\n\n购买渠道：\n- Pineapple Store（官方）\n- 京东/天猫Pineapple旗舰店\n- 授权经销商\n\n注意：价格可能因促销活动有所变动', '价格,多少钱,型号,购买', '官网'),
('产品对比', 'AirPods适合运动用吗？', '运动使用建议：\n\n适合的型号：\n- AirPods Pro：抗汗抗水，佩戴稳固\n- AirPods（第3代）：抗汗抗水\n\n不适合的型号：\n- AirPods Max：太重，不防水\n- AirPods（第1/2代）：不防水\n\n运动注意事项：\n1. 确保佩戴稳固\n2. 避免大量汗水直接接触\n3. 运动后清洁干燥\n4. 不要戴着游泳或淋浴', '运动,健身,防水,跑步', '用户反馈');
